custom_css:
[data-doctype="Web Form"] .page-content-wrapper .container .page_content {
    max-width: 1200px;
}

div[data-fieldname="plans"] .grid-body .grid-row .col:not([data-fieldname="new_qty"]),
div[data-fieldname="plans"] .grid-body .grid-row .col:not([data-fieldname="new_qty"]) input {
    background: var(--subtle-accent) !important;
    background-color: var(--subtle-accent) !important;
}

div[data-fieldname="plans"] .grid-heading-row .grid-row .col[data-fieldname="new_qty"],
div[data-fieldname="plans"] .grid-heading-row .grid-row .col[data-fieldname="new_amount"] {
    background: var(--bg-blue) !important;
    background-color: var(--bg-blue) !important;
    font-weight: bold !important;
    color: var(--text-on-dark-blue) !important;
}

div[data-fieldname="plans"] .grid-body .grid-row .col[data-fieldname="new_qty"],
div[data-fieldname="plans"] .grid-body .grid-row .col[data-fieldname="new_qty"] input {
    border-bottom: 2px solid var(--bg-dark-blue);
}

div[data-fieldname="plans"] .grid-body .grid-row .col[data-fieldname="new_amount"],
div[data-fieldname="plans"] .grid-body .grid-row .col[data-fieldname="new_amount"] input {
    background: var(--bg-light-blue) !important;
    background-color: var(--bg-light-blue) !important;
    color: var(--text-on-light-blue) !important;
}

/* hide breadcrumbs, add row button and row checkbox and edit button */
.breadcrumb-container,
div[data-fieldname="plans"] .row-check,
div[data-fieldname="plans"] .grid-heading-row .data-row > .col:last-child,
div[data-fieldname="plans"] .grid-body .data-row > .col:last-child,
div[data-fieldname="plans"] .grid-footer * {
    display: none !important;
    pointer-events: none !important;
    opacity: 0 !important;
}

/* shrink index column and other read only columns to focus on new values */
div[data-fieldname="plans"] .row-index,
div[data-fieldname="plans"] .grid-static-col[data-fieldname="price"],
div[data-fieldname="plans"] .grid-static-col[data-fieldname="qty"],
div[data-fieldname="plans"] .grid-static-col[data-fieldname="amount"]{
    flex: 0 0 8.33333333%;
    max-width: 8.33333333%;
}

/* expand plan column */
div[data-fieldname="plans"] .grid-static-col[data-fieldname="plan"] {
    flex: 0 0 33.33333333%;
    max-width: 33.33333333%;
}

div[data-fieldname="plans"] .grid-static-col[data-fieldname="new_qty"] {
    flex: 0 0 16.66666667%;
    max-width: 16.66666667%;
}


/* force colum headers to unwrap */
div[data-fieldname="plans"] .ellipsis {
    overflow: visible;
    white-space: normal;
    text-overflow: clip;
}
